import SwiftUI
import Foundation

struct Artwork: Identifiable {
    let id: String               // stable key for persistence
    let fileName: String         // SVG filename without extension
    let displayName: String      // human-readable name shown in UI
    let completionMessage: String
    let month: Int               // 1-12  anchor month
    let day: Int                 // 1-31  anchor day
}

extension Artwork {

    // MARK: - Curated Calendar

    /// 366 artworks ordered chronologically (Jan → Dec).
    /// Each artwork anchors to a specific (month, day) and remains the
    /// daily artwork until the next entry's date arrives.
    /// Placement reflects seasonal imagery, cultural resonance, and the
    /// rhythm of the natural world — without endorsing specific holidays.
    static let catalog: [Artwork] = [

                // ── January — Deep winter, fresh start ──────────────────────

        Artwork(id: "owlFull", fileName: "owlFull", displayName: "The Stare That Started It All",    completionMessage: "Owl eyes aren't spheres — they're tubes, locked in place. That unblinking stare is hardware, not attitude. The whole head turns instead.",    month: 1,  day: 1),
        Artwork(id: "frozenWaterfallCanyon", fileName: "frozenWaterfallCanyon", displayName: "The First Light Falls",    completionMessage: "A frozen waterfall isn't truly still — water keeps flowing inside the ice, and the whole thing pops and groans all winter. Stillness is mostly the cold's idea.",    month: 1,  day: 2),
        Artwork(id: "penguinIceberg",        fileName: "penguinIceberg",        displayName: "Huddled Against Everything",    completionMessage: "Emperor penguins huddle and rotate slowly through the night — every penguin takes a turn at the cold outer edge. No one freezes alone, by design.",    month: 1,  day: 3),
        Artwork(id: "shipwreckBeach",        fileName: "shipwreckBeach",        displayName: "What the Tide Keeps",    completionMessage: "Storms sometimes uncover wrecks the sand had hidden for a century. The seabirds move in within hours. The ocean files everything as theirs eventually.",    month: 1,  day: 4),
        Artwork(id: "foxHollowLog",          fileName: "foxHollowLog",          displayName: "The Warmest Spot in the Forest",    completionMessage: "Red foxes rarely dig their own dens — they move into ones other animals left behind. The hollow log is paid in mice and quiet.",    month: 1,  day: 5),
        Artwork(id: "pigeonManBench",        fileName: "pigeonManBench",        displayName: "The Regulars",    completionMessage: "Pigeons remember the faces of people who feed them. The same regulars get the same birds, week after week, year after year. They're keeping notes.",    month: 1,  day: 6),
        Artwork(id: "celloEmptyStage",       fileName: "celloEmptyStage",       displayName: "After the Last Note",    completionMessage: "Good cellos take decades to fully open up — the wood remembers every note and resonates better for it. Sound has a memory, kept in spruce and maple.",    month: 1,  day: 7),
        Artwork(id: "dogSledSunrise",        fileName: "dogSledSunrise",        displayName: "Full Speed at First Light",    completionMessage: "Sled dogs can run a hundred miles a day and burn ten thousand calories doing it. They pull because they love it — quitting is what hurts.",    month: 1,  day: 8),
        Artwork(id: "foxSnowMeadow",         fileName: "foxSnowMeadow",         displayName: "Gold Hour, Blue Shadow",    completionMessage: "Red foxes use Earth's magnetic field to pinpoint mice under three feet of snow. Pure GPS, no signal needed.",    month: 1,  day: 9),
        Artwork(id: "iceFishermanLake",      fileName: "iceFishermanLake",      displayName: "A Hole and a Hope",    completionMessage: "Ice fishing predates farming. The same hole, the same patience, ten thousand years running. Some pleasures don't need updating.",    month: 1,  day: 10),
        Artwork(id: "mooseHotSpring",        fileName: "mooseHotSpring",        displayName: "Chest-Deep and Unbothered",    completionMessage: "Moose use hot springs to thaw out and shed winter parasites. Half a ton of muscle, soaking in steam — a spa visit, with antlers.",    month: 1,  day: 11),
        Artwork(id: "snowyOwlMoonlight",     fileName: "snowyOwlMoonlight",     displayName: "Perched Above the Valley",    completionMessage: "Snowy owls hunt by daylight in summer and moonlight in winter — eyes built for both. The males turn whiter with each passing year.",    month: 1,  day: 12),
        Artwork(id: "snowLeopardMountain", fileName: "snowLeopardMountain", displayName: "The Ghost of the Ridge",    completionMessage: "Snow leopards carry tails as long as their bodies — for balance on cliffs and for wrapping around their faces in storms. Built for the heights.",    month: 1, day: 13),
        Artwork(id: "snowyVillageDogWalk",   fileName: "snowyVillageDogWalk",   displayName: "Footprints and Chimney Smoke",    completionMessage: "Walking a dog at night is older than the village itself — both grew up around the same fires. Some routines pre-date the streets they're on.",    month: 1,  day: 14),
        Artwork(id: "vinylRainCat",          fileName: "vinylRainCat",          displayName: "The Crackle Before the Music",    completionMessage: "Vinyl outsold CDs in 2022 for the first time since the 1980s. Some sounds want company: rain on glass, a needle finding the groove.",    month: 1,  day: 15),
        Artwork(id: "snowBridgeUmbrella", fileName: "snowBridgeUmbrella", displayName: "One Umbrella, One Bridge",    completionMessage: "Umbrellas were status symbols for centuries before they were practical. Crossing a bridge with one used to be a whole announcement.",    month: 1, day: 16),
        Artwork(id: "lighthouseKeeper",      fileName: "lighthouseKeeper",      displayName: "The Keeper Reads Alone",    completionMessage: "The last manned American lighthouse retired its keeper in 2002. Until then, somebody read by candlelight through every storm — for the ships nobody else could see.",    month: 1,  day: 17),
        Artwork(id: "bookshopSnow",          fileName: "bookshopSnow",          displayName: "The Sleeping Shopkeeper",    completionMessage: "Bookshop cats have been keeping mice off the shelves for centuries. Most are named after authors. None of them have read the books.",    month: 1,  day: 18),
        Artwork(id: "cardinalsFencePost",    fileName: "cardinalsFencePost",    displayName: "Red Against Everything",    completionMessage: "Cardinals don't migrate. The same pair holds the same yard through every winter, the red looking brighter against snow than it really is.",    month: 1,  day: 19),
        Artwork(id: "barnOwlMoonlight",      fileName: "barnOwlMoonlight",      displayName: "Silent Wings, Full Moon",    completionMessage: "Barn owls fly silently because every wing feather is fringed and velvety — sound-cancelling by design. No prey ever hears them coming.",    month: 1,  day: 20),
        Artwork(id: "abandonedGreenhouse",   fileName: "abandonedGreenhouse",   displayName: "One Orchid Refused",    completionMessage: "Orchids can outlive the buildings around them. After the greenhouse goes, sometimes one keeps blooming through the broken glass.",    month: 1,  day: 21),
        Artwork(id: "snowMonkeyHotSpring",   fileName: "snowMonkeyHotSpring",   displayName: "Bliss with Snow on Your Head",    completionMessage: "Snow monkeys learned to bathe in hot springs by watching humans in the 1960s. The whole troop adopted it within a generation. They were paying attention.",    month: 1,  day: 22),
        Artwork(id: "wolfPackMoonlight",     fileName: "wolfPackMoonlight",     displayName: "Single File, No Complaints",    completionMessage: "Wolves walk single-file through deep snow, taking turns breaking trail. The hardest job rotates — even the alpha steps back.",    month: 1,  day: 23),
        Artwork(id: "snowmanBackyard",       fileName: "snowmanBackyard",       displayName: "Carrot Nose, Red Scarf, No Plans",    completionMessage: "The earliest known snowman appears in a 1380 Dutch sketch. People have been giving them faces and names for at least six hundred years — a small ritual against the cold.",    month: 1,  day: 24),
        Artwork(id: "conservatoryPiano",     fileName: "conservatoryPiano",     displayName: "Keys in the Greenhouse",    completionMessage: "A grand piano has over twelve thousand parts. Most of them are wood, hand-fitted, holding tension against each other. Music is what they do when they agree.",    month: 1,  day: 25),
        Artwork(id: "walrusBeach",           fileName: "walrusBeach",           displayName: "Tangerine Sun, Two Tons",    completionMessage: "A walrus's whiskers are sensitive enough to find clams in pitch-dark mud. Two tons of bulk, with the touch of a fingertip.",    month: 1,  day: 26),
        Artwork(id: "lighthouseSnowstorm",   fileName: "lighthouseSnowstorm",   displayName: "The Beam Cuts Through",    completionMessage: "Before 1822, lighthouses could only be seen from a few miles. The Fresnel lens made one beam carry twenty. The whole coast got brighter overnight.",    month: 1,  day: 27),
        Artwork(id: "winterBridgeIcicles",   fileName: "winterBridgeIcicles",   displayName: "Icicles and Deer Tracks",    completionMessage: "Covered bridges last centuries because the roof keeps the wood dry. The covering wasn't romance — it was bookkeeping. They lasted anyway.",    month: 1,  day: 28),
        Artwork(id: "belugaAurora",          fileName: "belugaAurora",          displayName: "White Ghosts, Green Light",    completionMessage: "Belugas are called the canaries of the sea — they whistle, click, and chirp constantly to one another. A whole conversation, mostly under ice.",    month: 1,  day: 29),
        Artwork(id: "sealPupIce",            fileName: "sealPupIce",            displayName: "Round and Unbothered",    completionMessage: "Harp seal pups are born with white fur for two weeks of camouflage on the ice — then it molts to gray. Disguise has a deadline.",    month: 1,  day: 30),
        Artwork(id: "ravenGargoyle",         fileName: "ravenGargoyle",         displayName: "The High Perch",    completionMessage: "Ravens hold something like funerals — they gather around their dead in silence before flying off. Few birds we know of mourn so visibly.",    month: 1,  day: 31),

                // ── February — Winter continues, introspection ──────────────

        Artwork(id: "heronFrozenMarsh",      fileName: "heronFrozenMarsh",      displayName: "Still as the Cattails",    completionMessage: "Great blue herons can hold a single pose for hours — vertebrae locked, hunting by patience. The marsh freezes around them and they don't move.",    month: 2,  day: 1),
        Artwork(id: "groundhogDay",          fileName: "groundhogDay",          displayName: "The Reluctant Prophet",    completionMessage: "Groundhogs hibernate for five months, body temperature dropping to forty-one degrees. Whatever they see when they wake up looks brand new every February.",    month: 2,  day: 2),
        Artwork(id: "iceSkatingTwilight",    fileName: "iceSkatingTwilight",    displayName: "Blades and Fairy Lights",    completionMessage: "The first ice skates were carved from bone, four thousand years ago, on Scandinavian lakes. People have been gliding across frozen water for as long as there's been winter.",    month: 2,  day: 3),
        Artwork(id: "typewriterRain",        fileName: "typewriterRain",        displayName: "Half a Letter, Cold Coffee",    completionMessage: "QWERTY was designed in 1873 to slow typists down — fast keys jammed the mechanical arms. The keyboard you use still inherits a problem nobody has anymore.",    month: 2,  day: 4),
        Artwork(id: "valentineFlowerShop",   fileName: "valentineFlowerShop",   displayName: "Roses by the Bucket",    completionMessage: "About 250 million roses are grown for Valentine's Day each year — most of them in Kenya and Colombia, flown overnight to bloom on schedule.",    month: 2,  day: 5),
        Artwork(id: "sugarShackMaple",       fileName: "sugarShackMaple",       displayName: "Winter Turning Liquid",    completionMessage: "Forty gallons of maple sap boil down to one gallon of syrup. The season is four to six weeks long — winter giving up its sweetness slowly, all at once.",    month: 2,  day: 6),
        Artwork(id: "spiceMarketBoy",        fileName: "spiceMarketBoy",        displayName: "Above the Pyramids of Pepper",    completionMessage: "The smell of cumin and cardamom in a spice market hasn't changed in three thousand years. Pointing at things you don't recognize yet is also that old.",    month: 2,  day: 7),
        Artwork(id: "stagFogCrow",           fileName: "stagFogCrow",           displayName: "Crowned at the Edge",    completionMessage: "Crows sometimes ride deer through the woods, picking parasites from their fur. The bargain works for both — neither minds being still for the other.",    month: 2,  day: 8),
        Artwork(id: "craneDanceSnow",        fileName: "craneDanceSnow",        displayName: "Wings Wide, Snow Falling",    completionMessage: "Cranes dance for their partners — leaping, calling, mirroring each other through the snow. Pairs perform every winter for decades, even when no one is watching.",    month: 2,  day: 9),
        Artwork(id: "womanTrainWinter",      fileName: "womanTrainWinter",      displayName: "Going Somewhere Without Arriving",    completionMessage: "Trains were the first place strangers spent hours together in silence and were okay with it. A genre of solitude that needed a window.",    month: 2,  day: 10),
        Artwork(id: "bisonBlizzard",         fileName: "bisonBlizzard",         displayName: "Ice in Its Beard",    completionMessage: "A bison's coat insulates so well that snow piles up on its back without melting. They hold their own warmth, even when the storm tries to take it.",    month: 2,  day: 11),
        Artwork(id: "trainPlatformRain",     fileName: "trainPlatformRain",     displayName: "Waiting for Something",    completionMessage: "Train stations are designed for waiting — high ceilings, long benches, the rush absorbed before it reaches you. Architecture for arrivals that take their time.",    month: 2,  day: 12),
        Artwork(id: "swansIceHeart",         fileName: "swansIceHeart",         displayName: "Two Through the Thaw",    completionMessage: "Swans pair for life and form a heart with their necks when facing each other. The shape is real, not coincidence — courtship that draws its own emoji.",    month: 2,  day: 13),
        Artwork(id: "flamingoSunset",     fileName: "flamingoSunset",     displayName: "One Leg, No Worries",         completionMessage: "Flamingos are born gray. The pink comes from what they eat — carotenoids in algae and tiny shrimp. They are, almost literally, what they eat.",                       month: 2,  day: 14),
        Artwork(id: "mardiGrasMasks",     fileName: "mardiGrasMasks",     displayName: "Faces for the Forgetting",       completionMessage: "Mardi Gras parade riders are required by law to wear masks in New Orleans. A statute that protects the spectacle — once the mask is on, the float is the story.",               month: 2,  day: 15),
        Artwork(id: "lynxSnow",          fileName: "lynxSnow",          displayName: "Tufted and Watching",             completionMessage: "A lynx's ear tufts work like directional microphones — tuning small rustles in the snow. They hunt by hearing first, sight second.",              month: 2,  day: 16),
        Artwork(id: "robinNestEggs",         fileName: "robinNestEggs",         displayName: "Four Blue Promises",    completionMessage: "Robin egg blue comes from biliverdin — a pigment that may shield the embryos inside from too much sunlight. The color does a job.",    month: 2,  day: 17),
        Artwork(id: "watermillWinter",       fileName: "watermillWinter",       displayName: "The Frozen Wheel",    completionMessage: "Some watermills have been grinding grain in continuous operation since the eleventh century. The wheel freezes some winters and the chimney still smokes.",    month: 2,  day: 18),
        Artwork(id: "skiGondolaSunset",      fileName: "skiGondolaSunset",      displayName: "Suspended Between Earth and Sky",    completionMessage: "The first ski lift opened in Idaho in 1908 — a lazy solution invented by people whose sport was hiking up mountains on skis. A genius compromise.",    month: 2,  day: 19),
        Artwork(id: "underwaterShipwreck",fileName:"underwaterShipwreck",displayName:"What the Sea Keeps",  completionMessage: "Coral reefs colonize sunken ships within decades, turning steel into ecosystem. The ocean has its own way of forgiving.",           month: 2,  day: 20),
        Artwork(id: "redPandaBambooSnow",    fileName: "redPandaBambooSnow",    displayName: "Zero Urgency at Elevation",    completionMessage: "Red pandas are the only living members of their family — not bears, not raccoons, not pandas. A whole genus condensed into one shy creature in bamboo.",    month: 2,  day: 21),
        Artwork(id: "fishingBoatDawn",       fileName: "fishingBoatDawn",       displayName: "Before the World Wakes Up",    completionMessage: "Lobster traps have barely changed since colonial New England. Some fishing boat designs run unbroken for two centuries — fishermen are conservative for good reason.",    month: 2,  day: 22),
        Artwork(id: "gondolaSkiLift",     fileName: "gondolaSkiLift",     displayName: "Up and Then Down",       completionMessage: "A gondola cable holds tons of moving weight at once — six up, six down, every minute. The mountain made simpler than it actually is.",                 month: 2,  day: 23),
        Artwork(id: "machuPicchuLlama",  fileName: "machuPicchuLlama",  displayName: "Golden Fields, Quiet House",    completionMessage: "Sunflowers face east at dawn, then track the sun across the sky all day. By evening they're aimed west, ready to do it again. The whole field, in agreement.",               month: 2,  day: 24),
        Artwork(id: "mountainLakeReflection", fileName: "mountainLakeReflection", displayName: "The Mirror Basin", completionMessage: "Mirror lakes form when wind drops below 2 mph. The water becomes glass and the mountain doubles. Stillness has a wind speed.", month: 2, day: 25),
        Artwork(id: "violinistArchway",      fileName: "violinistArchway",      displayName: "Strings Under Stone",    completionMessage: "Stradivarius violins use spruce that grew slowly during a 17th-century cold spell — denser wood, richer tone. Modern luthiers can't quite match what climate did for free.",    month: 2,  day: 26),
        Artwork(id: "winterGardenGate",  fileName: "winterGardenGate",  displayName: "A Door to the Dormant",     completionMessage: "Winter is when most plants do their underground work. The dormant garden is rebuilding roots. What looks like sleep is the longest patient effort.",              month: 2,  day: 27),
        Artwork(id: "wolverineSnow", fileName: "wolverineSnow", displayName: "Thirty Pounds of Don't",    completionMessage: "Wolverines drive grown bears off their food. Pound for pound, they have one of the strongest bites of any mammal — fearlessness with fur.",    month: 2, day: 28),
        Artwork(id: "winterTownSnowman",fileName:"winterTownSnowman",displayName: "The Watcher of the Square",    completionMessage: "February 29 only happens because Earth's year runs six hours longer than 365 days. Without the leap, our calendars would drift a day every four years. The snowman gets a rare extra shift.",       month: 2,  day: 29),

                // ── March — Thaw, awakening ─────────────────────────────────

        Artwork(id: "hareSpringThaw",     fileName: "hareSpringThaw",     displayName: "The Leap Between Seasons",    completionMessage: "Hares are born with eyes open and full fur, ready to outrun trouble within hours. Spring doesn't wait, and neither do they.",            month: 3,  day: 1),
        Artwork(id: "bookshopLadder",        fileName: "bookshopLadder",        displayName: "Stories Floor to Ceiling",    completionMessage: "Rolling ladders for tall bookshelves date back to the 1600s. The cat in the window predates the lamp by even longer.",    month: 3,  day: 2),
        Artwork(id: "robinNestBlossoms", fileName: "robinNestBlossoms", displayName: "The Careful Engineers", completionMessage: "Robins use mud to bind their grass nests — a recipe passed down for thousands of years. Architecture without an architect.",         month: 3,  day: 3),
        Artwork(id: "cardinalFrostBranch", fileName: "cardinalFrostBranch", displayName: "The Branch That Held",    completionMessage: "Cardinals are one of the few North American songbirds where the female also sings — usually from the nest, calling the male to bring food. A duet through winter.",    month: 3, day: 4),
        Artwork(id: "bearSalmonRiver",       fileName: "bearSalmonRiver",       displayName: "Last Catch of the Season",    completionMessage: "Bears eat the fattiest parts of salmon — brain, skin, eggs — and leave the rest for eagles, foxes, and the forest itself. The whole watershed runs on what bears don't finish.",    month: 3,  day: 5),
        Artwork(id: "cherryBlossomPond",     fileName: "cherryBlossomPond",     displayName: "Petals on Still Water",    completionMessage: "Sakura viewing has been a public ritual in Japan since the 8th century. The blossoms last a week. People still rearrange their lives to be there.",    month: 3,  day: 6),
        Artwork(id: "ladybugLeaf",     fileName: "ladybugLeaf",    displayName: "Seven Spots, Zero Regrets",        completionMessage: "A single ladybug eats five thousand aphids in its lifetime. Farmers buy them by the thousand to keep gardens alive. Tiny industrial workers, in red.",              month: 3,  day: 7),
        Artwork(id: "paperBoatGutter",       fileName: "paperBoatGutter",       displayName: "Fleet of the Gutter",    completionMessage: "Origami paper boats float surprisingly well — a tight fold sheds water for hours. Kids in every culture seem to invent the same fleet.",    month: 3,  day: 8),
        Artwork(id: "ottersThawingRiver", fileName: "ottersThawingRiver", displayName: "Loose in the Current",completionMessage: "Sea otters hold hands while sleeping so they don't drift apart. Many keep a favorite stone tucked under one arm — the same stone, sometimes for life.",                 month: 3,  day: 9),
        Artwork(id: "ramenBarTokyo",         fileName: "ramenBarTokyo",         displayName: "The Right Place at Midnight",    completionMessage: "Ramen came from China to Japan in the early 1900s and never left. There are over thirty-five thousand ramen shops in Japan now — most of them this size, this steamy, this serious.",    month: 3,  day: 10),
        Artwork(id: "amsterdamSpringTulips", fileName: "amsterdamSpringTulips", displayName: "The First Warm Day",    completionMessage: "In 1637, a single tulip bulb could cost a year's salary. The bubble crashed. The flowers stayed, blooming in window boxes ever since — much cheaper now.",    month: 3,  day: 11),
        Artwork(id: "kingfisher",         fileName: "kingfisher",         displayName: "The Feathered Bolt",             completionMessage: "Kingfishers can see straight through water — their eyes correct for the refraction, then they dive at 25 mph. The fish never see them coming.",                             month: 3,  day: 12),
        Artwork(id: "backyardWatchParty",    fileName: "backyardWatchParty",    displayName: "The Big Screen, The Small Yard",    completionMessage: "Backyard projectors finally got cheap in the 2010s. Suddenly anyone with a sheet and an extension cord could host a drive-in. The grill came along for free.",    month: 3,  day: 13),
        Artwork(id: "japaneseGarden",    fileName: "japaneseGarden",    displayName: "Still Water, Still Mind",        completionMessage: "Some Japanese gardens have been continuously maintained for eight hundred years. Each generation rakes the same gravel into the same patterns. The instructions live in the rake.",                    month: 3,  day: 14),
        Artwork(id: "deerWinterSpring",      fileName: "deerWinterSpring",      displayName: "Steam and Thirst",    completionMessage: "White-tailed deer can lose nearly a third of their body weight by spring. The first thaw and the first unfrozen water are the year's most important meal.",    month: 3,  day: 15),
        Artwork(id: "greenhouseSeedlings",fileName:"greenhouseSeedlings",displayName:"The Patient Beginning",  completionMessage: "Some seeds wait. Lotus seeds have sprouted after a thousand years. Patience is built in — the greenhouse just gets to skip ahead.",                   month: 3,  day: 16),
        Artwork(id: "irishHillside",     fileName: "irishHillside",     displayName: "Forty Shades and Then Some",    completionMessage: "Ireland's plants show forty distinct shades of green in spring. The damp climate turns every leaf its own version. The country earned its reputation honestly.",  month: 3,  day: 17),
        Artwork(id: "santoriniLetter",       fileName: "santoriniLetter",       displayName: "Blue Domes and Longing",    completionMessage: "Santorini's white walls and blue domes aren't aesthetic — white reflects the heat, blue traditionally marks the churches. Beauty, by way of practical engineering.",    month: 3,  day: 18),
        Artwork(id: "seahorseSeagrass",fileName:"seahorseSeagrass",displayName:"Curled in the Current",  completionMessage: "Male seahorses carry the eggs and give birth. They mate for life and greet their partner with a daily dance. Almost everything about them is unusual.",   month: 3,  day: 19),
        Artwork(id: "polarBearAurora2",    fileName: "polarBearAurora2",    displayName: "Aurora and Instinct",    completionMessage: "Polar bear fur is actually clear, not white. Each hollow strand traps light and reflects it, making them appear white while keeping them warm in the dark.",     month: 3,  day: 20),
        Artwork(id: "chameleonBranch", fileName: "chameleonBranch", displayName: "Currently Undecided",    completionMessage: "Chameleons change color to communicate mood, not to hide. Their eyes move independently — two scenes at once, no overlap. They see twice as much as we do.",    month: 3, day: 21),
        Artwork(id: "netMenderDock",         fileName: "netMenderDock",         displayName: "Knots and Patience",    completionMessage: "Fishing nets use knots that haven't changed in three thousand years. The fisherman mending one is performing one of the oldest small repairs there is.",    month: 3,  day: 22),
        Artwork(id: "rainBenchLamp", fileName: "rainBenchLamp", displayName: "Wet Bench, Warm Light",    completionMessage: "A park bench in the rain under a streetlamp. No one is sitting here. It's perfect that way.",    month: 3, day: 23),
        Artwork(id: "seaTurtleCoral",   fileName: "seaTurtleCoral",   displayName: "Ancient and Unhurried",        completionMessage: "Sea turtles return to the same beach where they were born to lay their eggs. They find it from oceans away.",   month: 3,  day: 24),
        Artwork(id: "brownBearSnow",fileName:"brownBearSnow",displayName:"The Bear in the Snow",    completionMessage: "Brown bears can smell food from twenty miles away. They know you're there before you see them.",            month: 3,  day: 25),
        Artwork(id: "nautilusShell", fileName: "nautilusShell", displayName: "The Oldest Blueprint",    completionMessage: "A nautilus shell. Five hundred million years, and it still gets compliments.",    month: 3, day: 26),
        Artwork(id: "ravenFoggyValley",  fileName: "ravenFoggyValley",  displayName: "The Black Messenger",  completionMessage: "Ravens recognize human faces. They tell their friends about us. You just made a good impression.",             month: 3,  day: 27),
        Artwork(id: "hawkVineyard",  fileName: "hawkVineyard",  displayName: "The Vineyard Watch",           completionMessage: "Hawks can spot prey from a mile away. Vineyards welcome them — they keep rabbits off the grapes for free, no contract needed.",                        month: 3,  day: 28),
        Artwork(id: "beachedTrawler",  fileName: "beachedTrawler",  displayName: "The Beached Trawler",          completionMessage: "Beached trawlers turn into ecosystems within a year. Barnacles, birds, beach grass — the boat dies into a coastline. A retirement plan, in driftwood.",           month: 3,  day: 29),
        Artwork(id: "rowboatTwilight",      fileName: "rowboatTwilight",      displayName: "Rowboat at Twilight",             completionMessage: "Dragonflies have been around for three hundred million years — they predate dinosaurs. The same shape was working long before lakes had names.",        month: 3,  day: 30),
        Artwork(id: "estuaryGoldenHour",   fileName: "estuaryGoldenHour",   displayName: "Where the River Meets Gold",           completionMessage: "Estuaries are among the most productive ecosystems on Earth — more biodiverse per acre than tropical rainforests. Where fresh water meets salt, life accelerates.",        month: 3,  day: 31),

                // ── April — Full spring, blossoms ───────────────────────────

        Artwork(id: "kiwiBirdNight", fileName: "kiwiBirdNight", displayName: "No Wings, No Regrets",    completionMessage: "Kiwis are the only birds with nostrils at the tip of their beaks — they sniff the ground for worms. They also lay eggs that are 20% of their body weight.",    month: 4, day: 1),
        Artwork(id: "rainforestWaterfall",fileName:"rainforestWaterfall",displayName:"Cascade Without End",   completionMessage: "A waterfall does more than fall — it aerates the river below, oxygenating water for the fish that live in it. The work is in the noise.",               month: 4,  day: 2),
        Artwork(id: "redPanda",            fileName: "redPanda",            displayName: "The Russet Daydreamer",              completionMessage: "Red pandas have a false thumb — an extra wrist bone evolved just for gripping bamboo. They've been figuring it out for fifty million years.",                              month: 4,  day: 3),
        Artwork(id: "peacockMandala",     fileName: "peacockMandala",      displayName: "Every Feather an Eye",     completionMessage: "Peacock feathers contain almost no pigment. The iridescence comes from nanostructures bending light — the colors aren't painted on, they're built in.",                   month: 4,  day: 4),
        Artwork(id: "easterGarden",       fileName: "easterGarden",       displayName: "Hidden in Plain Sight",         completionMessage: "Decorated eggs date back five thousand years — Sumerian, then Egyptian, then medieval Europe. Spring has been celebrated by drawing on shells longer than most languages have existed.",                  month: 4,  day: 5),
        Artwork(id: "rogueWave",    fileName: "rogueWave",     displayName: "The Rogue Swell",      completionMessage: "Rogue waves were sailor mythology until 1995, when an oil platform finally measured one — 84 feet tall in calm seas. The ocean was telling the truth all along.",            month: 4,  day: 6),
        Artwork(id: "poisonDartFrogBlue",           fileName: "poisonDartFrogBlue",           displayName: "Neon and Deadly",             completionMessage: "Captive-bred poison dart frogs are harmless — their toxins come from wild ants and mites. The bright color is a warning only honest frogs can keep.",                   month: 4,  day: 7),
        Artwork(id: "hummingbirdTrumpetVine", fileName: "hummingbirdTrumpetVine", displayName: "Jeweled and Frozen Mid-Beat",    completionMessage: "A hummingbird's heart beats 1,200 times a minute. They visit a thousand flowers a day, remembering which ones they've drained and when each one refills.",    month: 4,  day: 8),
        Artwork(id: "nautilusSpiral",    fileName: "nautilusSpiral",    displayName: "The Spiral Chamber",       completionMessage: "A nautilus controls its depth by adjusting gas in its old chambers — a biological submarine, five hundred million years before we built one.",                       month: 4,  day: 9),
        Artwork(id: "venetianMaskMaker",     fileName: "venetianMaskMaker",     displayName: "The Craft of Becoming Someone Else",    completionMessage: "Venetian masks were worn for nearly half the year historically. Classes mixed because no one could tell who anyone was. The disguise was the freedom.",    month: 4,  day: 10),
        Artwork(id: "rangoliPattern",        fileName: "rangoliPattern",        displayName: "Powder and Petals",           completionMessage: "A new rangoli is drawn fresh each morning at the threshold and swept away by night. The daily impermanence is part of the welcome.",                        month: 4,  day: 11),
        Artwork(id: "bicycleCafe",     fileName: "bicycleCafe",     displayName: "Le Vélo de Personne",         completionMessage: "Paris now has more bicycles than cars on its streets. After 2020 the city built so many new bike lanes that the rhythm of the city quietly rearranged itself.",                          month: 4,  day: 12),
        Artwork(id: "octopusDeep",     fileName: "octopusDeep",     displayName: "Eight Arms, No Apologies",        completionMessage: "Octopuses change skin texture as well as color, and may also dream — color flickers across them while they sleep. Eight arms and a private movie.",          month: 4,  day: 13),
        Artwork(id: "narwhalArctic",      fileName: "narwhalArctic",      displayName: "The Unicorn of the Sea",         completionMessage: "A narwhal's tusk has ten million nerve endings — it senses water temperature, salinity, even pressure. Less weapon, more antenna.",                                     month: 4,  day: 14),
        Artwork(id: "scarletMacaw",          fileName: "scarletMacaw",          displayName: "Loud, Proud, and Primary",             completionMessage: "Scarlet macaws eat clay daily from riverbanks — it neutralizes toxins in their unripe-fruit diet. They figured out chemistry without writing it down.",               month: 4,  day: 15),
        Artwork(id: "prayingMantis",      fileName: "prayingMantis",      displayName: "The Ambush Artist",        completionMessage: "Praying mantises are the only insects that can swivel their heads to look behind them. The stillness isn't waiting. It's tracking.",      month: 4,  day: 16),
        Artwork(id: "nightMarketSoup",       fileName: "nightMarketSoup",       displayName: "Steam and Bare Bulbs",    completionMessage: "Night markets trace back to Song dynasty China — they run because the heat fades, the food cools, and people gather. A pattern that worked then, still works now.",    month: 4,  day: 17),
        Artwork(id: "armadilloDesert",    fileName: "armadilloDesert",    displayName: "Armored and Unbothered",        completionMessage: "Armadillos can hold their breath for six minutes and walk underwater across riverbeds. Bony armor with surprise inside.",             month: 4,  day: 18),
        Artwork(id: "chessInThePark",        fileName: "chessInThePark",        displayName: "Dappled Light, Deep Thought",    completionMessage: "Chess in city parks is a global tradition. Some of the regulars are former masters playing for coffee, surprising tourists who don't know the table they sat at.",    month: 4,  day: 19),
        Artwork(id: "maroonTemple",       fileName: "maroonTemple",       displayName: "The Night Forager",          completionMessage: "The temple sits in morning mist like it's been meditating longer than anyone inside it.",                         month: 4,  day: 20),
        Artwork(id: "havanaRooftop",         fileName: "havanaRooftop",         displayName: "Laundry and Faded Pastels",    completionMessage: "Cuba's vintage American cars are still running because of half a century of improvisation. Soviet engines under American hoods, kept alive by hand.",    month: 4,  day: 21),
        Artwork(id: "harborLowTide",      fileName: "harborLowTide",      displayName: "Teeth and Attitude",     completionMessage: "Tides shift water in and out of harbors twice a day, every day. The Bay of Fundy moves a hundred billion tons of it — boats lifted and dropped on schedule.",                              month: 4,  day: 22),
        Artwork(id: "bambooForestPath",   fileName: "bambooForestPath",   displayName: "The Headfirst Approach",          completionMessage: "A thousand bamboo stalks and not two the same height. Sounds like a metaphor. Probably is.",                    month: 4,  day: 23),
        Artwork(id: "parisianCafe",      fileName: "parisianCafe",      displayName: "Rain, Bench, Nowhere to Be",          completionMessage: "Parisian sidewalk cafés are legally protected as cultural heritage. The wet bench, the lone customer, the rain — all of it is, technically, preserved.",          month: 4,  day: 24),
        Artwork(id: "porcupineAutumn",   fileName: "porcupineAutumn",    displayName: "Quills Raised, No Comment",            completionMessage: "A porcupine has thirty thousand quills — modified hairs, hollow inside, designed to detach on contact. The least apologetic defense in nature.",              month: 4,  day: 25),
        Artwork(id: "pelicanDive", fileName: "pelicanDive", displayName: "The Committed Approach",    completionMessage: "Pelicans dive from sixty feet and hit the water at forty miles an hour. Their pouch holds three gallons of water and fish at once. Total commitment.",    month: 4, day: 26),
        Artwork(id: "fennecFoxDusk",         fileName: "fennecFoxDusk",         displayName: "All Ears, No Chill",            completionMessage: "Fennec foxes use their oversized ears to radiate heat in the desert. They can also survive without drinking water — they get all of it from their food.",    month: 4,  day: 27),
        Artwork(id: "slotCanyon",            fileName: "slotCanyon",            displayName: "Light Finds a Way Down",    completionMessage: "Slot canyons are carved by flash floods over millions of years — water finding the same path again and again until the rock gives in.",    month: 4,  day: 28),
        Artwork(id: "heronCypress",    fileName: "heronCypress",    displayName: "Rookery in the Fog",            completionMessage: "Great blue herons stand motionless for hours, then strike in less than a second. Patience is its own kind of speed.",   month: 4,  day: 29),
        Artwork(id: "coyoteSunset",   fileName: "coyoteSunset",   displayName: "Coyote at the Golden Edge",           completionMessage: "Coyotes have quietly expanded into every state and most cities. They didn't ask for permission.",            month: 4,  day: 30),

                // ── May — Late spring, renewal ──────────────────────────────

        Artwork(id: "teaFarmerHills",        fileName: "teaFarmerHills",        displayName: "Basket Through the Mist",    completionMessage: "Tea is picked by hand because machines can't tell which leaves are ready. Every cup is someone's careful eye.",    month: 5,  day: 1),
        Artwork(id: "riceTerraces",       fileName: "riceTerraces",       displayName: "Staircase to the Sky",          completionMessage: "Two thousand years of hands shaped these. Each terrace holds up the one above it.",             month: 5,  day: 2),
        Artwork(id: "cappadociaBalloons", fileName: "cappadociaBalloons", displayName: "Drifting Without Itinerary",    completionMessage: "Cappadocia has more hot air balloons than anywhere on earth. They launch before sunrise, all at once, in silence.",                   month: 5,  day: 3),
        Artwork(id: "winterMarket",      fileName: "winterMarket",       displayName: "Lanterns in the Cold",         completionMessage: "Christmas markets started in the 1300s as a way to stock up before winter sealed the roads. Now we go for the glühwein.",               month: 5,  day: 4),
        Artwork(id: "swanGliding",        fileName: "swanGliding",        displayName: "The Effort Beneath",           completionMessage: "Swans mate for life and grieve their partners for months. Ducks do not. Different birds, different priorities.",                             month: 5,  day: 5),
        Artwork(id: "sailboatLake",     fileName: "sailboatLake",     displayName: "Still Water, Tall Sails",        completionMessage: "Sailing predates the wheel by thousands of years. The first boats were just leaves on water.",                      month: 5,  day: 6),
        Artwork(id: "driftwoodPebbles",   fileName: "driftwoodPebbles",   displayName: "What the Tide Left",  completionMessage: "Beach pebbles get rounder over centuries — every wave a tiny edit. Patience, in stone form.",                                    month: 5,  day: 7),
        Artwork(id: "countryBicycles",       fileName: "countryBicycles",       displayName: "Long Shadows, Short Plans",    completionMessage: "Bicycles changed who could go where. Before bikes, most people lived their whole lives within a few miles of where they were born.",    month: 5,  day: 8),
        Artwork(id: "weirdBird",          fileName: "weirdBird",          displayName: "Inexplicably Confident",           completionMessage: "Birds don't know they're weird-looking. They evolved to look exactly like this, on purpose, and consider it a victory.",                     month: 5,  day: 9),
        Artwork(id: "elephantFamily",     fileName: "elephantFamily",     displayName: "The Long Memory",        completionMessage: "Elephants greet each other after years apart with elaborate ceremonies. They recognize over a hundred individuals by voice.",             month: 5,  day: 10),
        Artwork(id: "robinStoneWall",    fileName: "robinStoneWall",    displayName: "Perched and Unimpressed",    completionMessage: "Robins were a sign of spring long before anyone wrote it down. They've been the same kind of news for centuries.",               month: 5,  day: 11),
        Artwork(id: "wildflowerMeadow",  fileName: "wildflowerMeadow",   displayName: "Everything at Once",     completionMessage: "A wildflower meadow has no designer. Each species shows up, takes its share of light, and somehow it all works.",        month: 5,  day: 12),
        Artwork(id: "prairieDogTown",     fileName: "prairieDogTown",     displayName: "Citizens of the Sightline",       completionMessage: "Prairie dogs have a language. Different barks for hawks, coyotes, humans — even the color of clothes.",                             month: 5,  day: 13),
        Artwork(id: "magnoliaBlossoms",  fileName: "magnoliaBlossoms",  displayName: "Before the Petals Fall",     completionMessage: "Magnolia trees predate bees. They evolved to be pollinated by beetles. Some things were here first.",               month: 5,  day: 14),
        Artwork(id: "redBridge",          fileName: "redBridge",          displayName: "Vermillion Crossing",             completionMessage: "A red bridge in a Japanese garden marks the threshold between worlds. Best crossed slowly.",                       month: 5,  day: 15),
        Artwork(id: "tadpolePond",       fileName: "tadpolePond",       displayName: "Everything Is Potential",           completionMessage: "Tadpoles grow legs first, then absorb their tails. They literally become a different animal in the same body.",                 month: 5,  day: 16),
        Artwork(id: "peacockGarden",      fileName: "peacockGarden",      displayName: "Unashamed Magnificence",    completionMessage: "A peacock's tail spots aren't real eyes — they evolved to scare predators. A thousand watchful eyes that aren't watching anything.",    month: 5,  day: 17),
        Artwork(id: "surferDawn",            fileName: "surferDawn",            displayName: "Board Under Arm, Sky Breaking",    completionMessage: "Hawaiians invented surfing as a spiritual practice — riding the breath of the sea. Some traditions made it across oceans intact.",    month: 5,  day: 18),
        Artwork(id: "englishCottage",     fileName: "englishCottage",     displayName: "Roses at the Door",        completionMessage: "Thatched roofs last fifty years and breathe in winter. Made of straw, somehow waterproof.",                        month: 5,  day: 19),
        Artwork(id: "pelicanPlunge",       fileName: "pelicanPlunge",       displayName: "The Plunge",               completionMessage: "Pelicans dive face-first from sixty feet. Their skulls have built-in airbags so the impact doesn't kill them.",       month: 5,  day: 20),
        Artwork(id: "apiaryGoldenHour",  fileName: "apiaryGoldenHour",  displayName: "The Hum of Industry",  completionMessage: "A single hive has 50,000 bees, all sisters, all working together. They give directions by dancing.",         month: 5,  day: 21),
        Artwork(id: "kayakLakeshore",    fileName: "kayakLakeshore",    displayName: "Paddle, Then Stillness",        completionMessage: "Kayaks are 4,000 years old. Inuit hunters built them from sealskin and driftwood. Engineering with what's available.",           month: 5,  day: 22),
        Artwork(id: "kingfisherDive",    fileName: "kingfisherDive",    displayName: "Arrow Into Blue",        completionMessage: "Engineers studied kingfishers to design Japan's bullet trains. The bird's beak shape made the trains quiet.",          month: 5,  day: 23),
        Artwork(id: "wheelbarrowCatNap",fileName: "wheelbarrowCatNap",displayName: "Nap Without Apology",    completionMessage: "Cats sleep about fifteen hours a day. The world hasn't fallen apart. Worth thinking about.",              month: 5,  day: 24),
        Artwork(id: "lavenderFarmer",    fileName: "lavenderFarmer",    displayName: "Rows of Purple, One Good Dog",    completionMessage: "Lavender repels mosquitoes and calms anxiety. Bees love it. The plant is just trying to be useful.",    month: 5,  day: 25),
        Artwork(id: "hotAirBalloonLavender",fileName:"hotAirBalloonLavender",displayName:"Adrift in Purple Fields", completionMessage: "The first hot air balloon flight carried a sheep, a duck, and a rooster. Flight-tested for safety.",            month: 5,  day: 26),
        Artwork(id: "outdoorMovieNight",fileName: "outdoorMovieNight",displayName: "Credits Under Stars",     completionMessage: "Drive-in movies peaked in the 1950s — over four thousand across America. About three hundred left now. Same stars overhead.",                              month: 5,  day: 27),
        Artwork(id: "beekeeperMeadow",       fileName: "beekeeperMeadow",       displayName: "Frame by Frame",    completionMessage: "A pound of honey takes 50,000 miles of bee travel and two million flower visits. Slow food in the original sense.",    month: 5,  day: 28),
        Artwork(id: "thunderstormSunflowers",fileName:"thunderstormSunflowers",displayName:"Before the Rain Hits",completionMessage:"Sunflowers face east in the morning, follow the sun, and end the day facing west. Solar tracking, perfected.",              month: 5,  day: 29),
        Artwork(id: "twilightHorizon",   fileName: "twilightHorizon",   displayName: "The Last Lit Edge",       completionMessage: "Sunset colors come from sunlight bouncing off particles in the atmosphere. The dustier the day, the more dramatic.",           month: 5,  day: 30),
        Artwork(id: "firefliesTwilight", fileName: "firefliesTwilight", displayName: "Punctuation of Light",  completionMessage: "Fireflies are disappearing — light pollution disrupts their mating signals. This one is doing fine.",                  month: 5,  day: 31),

                // ── June — Early summer, open landscapes ────────────────────

        Artwork(id: "hummingbirdGarden", fileName: "hummingbirdGarden", displayName: "Nectar and Velocity",     completionMessage: "A hummingbird's heart beats over a thousand times a minute. They have to eat every fifteen minutes just to keep it going.",                month: 6,  day: 1),
        Artwork(id: "dragonBoatRace",     fileName: "dragonBoatRace",     displayName: "Synchronized and Determined",       completionMessage: "Dragon boats have been raced for two thousand years, originally to summon a poet from the river. Synchronization keeps them straight.",                           month: 6,  day: 2),
        Artwork(id: "floatingMarket",     fileName: "floatingMarket",     displayName: "Commerce on the Water",        completionMessage: "Floating markets predate roads in much of Southeast Asia. Vendors still steer with one foot and sell with both hands.",                      month: 6,  day: 3),
        Artwork(id: "monetBridge",        fileName: "monetBridge",        displayName: "Impression of an Impression",           completionMessage: "Monet painted his garden bridge over two hundred and fifty times. As his cataracts worsened, the colors got wilder.",         month: 6,  day: 4),
        Artwork(id: "castle",             fileName: "castle",             displayName: "Ramparts at Dusk",                 completionMessage: "Tapestries inside medieval castles weren't decoration — they were insulation. Stone walls held the cold for months.",              month: 6,  day: 5),
        Artwork(id: "mossyWaterfall",     fileName: "mossyWaterfall",     displayName: "The Green Veil",        completionMessage: "Moss has been on Earth for four hundred and seventy million years — older than trees, older than bones.",                  month: 6,  day: 6),
        Artwork(id: "eidCourtyard",       fileName: "eidCourtyard",       displayName: "The Generous Season",           completionMessage: "Eid al-Adha is observed in coordinated time across the world. Right now, somewhere, someone is sharing the meal.",                month: 6,  day: 7),
        Artwork(id: "elephantSavanna",   fileName: "elephantSavanna",    displayName: "The Long Walk Home",       completionMessage: "Elephants visit the bones of relatives who died years before. They run their trunks over them, slowly, then move on.",                   month: 6,  day: 8),
        Artwork(id: "heronMoonlitLake",   fileName: "heronMoonlitLake",   displayName: "Silver Water, Still Wings",  completionMessage: "Great blue herons can stand motionless for over an hour. The stillness is the hunt.",               month: 6,  day: 9),
        Artwork(id: "goldenSailboat",     fileName: "goldenSailboat",     displayName: "Light on the Water",        completionMessage: "A sailboat can move into the wind at angles by working its keel against the water. Physics, not magic.",                     month: 6,  day: 10),
        Artwork(id: "hotAirBalloonFarmland",fileName:"hotAirBalloonFarmland",displayName:"Late Summer, Warm Windows",    completionMessage: "The first hot air balloon flight in 1783 carried a sheep, a duck, and a rooster. They survived. Humans went up next.",                   month: 6,  day: 11),
        Artwork(id: "treehouse",          fileName: "treehouse",          displayName: "Up Among the Leaves",              completionMessage: "The Korowai of Papua build their homes a hundred feet up in trees. They've done so for centuries.",                                  month: 6,  day: 12),
        Artwork(id: "puffinCliff",        fileName: "puffinCliff",        displayName: "Standing at the Edge",           completionMessage: "Puffins mate for life and return to the same burrow every spring. The cliff remembers them too.",              month: 6,  day: 13),
        Artwork(id: "ferrisWheelCarnival",fileName:"ferrisWheelCarnival",displayName:"Lights After Dark",  completionMessage: "The first Ferris Wheel was built in 1893 to outdo the Eiffel Tower. It held over two thousand people at once.",                 month: 6,  day: 14),
        Artwork(id: "tuscanRoad",         fileName: "tuscanRoad",         displayName: "The Road to Somewhere Warm",            completionMessage: "The cypress-lined roads of Tuscany were planted during the Renaissance — composition rather than coincidence.",          month: 6,  day: 15),
        Artwork(id: "wishingWellRoses", fileName: "wishingWellRoses", displayName: "A Wish Left Unspoken",     completionMessage: "Wishing wells began as Celtic offerings to water spirits. The coin is what's left of an old prayer.",  month: 6,  day: 16),
        Artwork(id: "venice",             fileName: "venice",             displayName: "The City on Still Water",                 completionMessage: "Venice rests on a forest of wooden piles, hammered into the lagoon a thousand years ago. They petrified instead of rotting.",                 month: 6,  day: 17),
        Artwork(id: "vintageBiplane",     fileName: "vintageBiplane",     displayName: "Before Everything Got Complicated",        completionMessage: "The first powered flight in 1903 lasted twelve seconds. Five years later, biplanes were carrying passengers across countries.",           month: 6,  day: 18),
        Artwork(id: "bicycleMorningGlories",fileName:"bicycleMorningGlories",displayName:"Morning Without Agenda",completionMessage: "Morning glories open at dawn and close before noon. They're not for evening admirers.", month: 6, day: 19),
        Artwork(id: "riverKayaking",     fileName: "riverKayaking",      displayName: "Into the Current",         completionMessage: "Whitewater kayakers learn to read currents the way readers learn punctuation. Every eddy is a comma.",         month: 6,  day: 20),
        Artwork(id: "fishingPierSunset",  fileName: "fishingPierSunset",  displayName: "The Last Cast of the Day", completionMessage: "Fishing piers reach exactly far enough to find where fish school. The distance is local knowledge, passed down.",               month: 6,  day: 21),
        Artwork(id: "trainStation",      fileName: "trainStation",       displayName: "Departures",          completionMessage: "Train stations standardized time. Before them, every town kept its own clock — railways forced the world to synchronize.",                   month: 6,  day: 22),
        Artwork(id: "fishVillage",        fileName: "fishVillage",        displayName: "Nets and Quiet Mornings",        completionMessage: "In some fishing villages, the day's catch is still divided by household need rather than who pulled it in. Old systems, still working.",                       month: 6,  day: 23),
        Artwork(id: "townChurch",         fileName: "townChurch",         displayName: "Sunday Light Through Stone",            completionMessage: "Stained glass windows were positioned so sunlight would land a certain way at certain hours. Architects of light.",                                 month: 6,  day: 24),
        Artwork(id: "heronGoldenMarsh",  fileName: "heronGoldenMarsh",  displayName: "Heron in the Golden Marsh",          completionMessage: "Herons hunt at first light because that's when fish stir. The hunt is timed to the fish's clock, not the bird's.",                 month: 6,  day: 25),
        Artwork(id: "coralLagoon",         fileName: "coralLagoon",         displayName: "Glass Water, Bright Sky",                  completionMessage: "Coral lagoons form behind reefs that broke the waves for centuries. The calm water is what's left of that wall.",                             month: 6,  day: 26),
        Artwork(id: "hermitCrabBeach",     fileName: "hermitCrabBeach",     displayName: "The Borrowed Shell",              completionMessage: "Hermit crabs upgrade shells in lines. When a bigger one appears, they queue by size and everyone moves up at once.",                   month: 6,  day: 27),
        Artwork(id: "ciderPressBarn",    fileName: "ciderPressBarn",    displayName: "October in the Rafters",       completionMessage: "In early America, cider was safer than water. Most farms had a press; most days began with a cup of it.",                      month: 6,  day: 28),
        Artwork(id: "redSquirrelPinecone",fileName:"redSquirrelPinecone",displayName:"Small Ambitions, Sharp Teeth",          completionMessage: "Red squirrels store pinecones in cool, damp soil. The seeds inside stay fresh for months — a fridge that doesn't need plugging in.",     month: 6,  day: 29),
        Artwork(id: "treeFrogStare", fileName: "treeFrogStare", displayName: "The Green Watching",         completionMessage: "Tree frogs have suction-cup toes that grip glass. Some species are nearly transparent — you can see their hearts beat.",                  month: 6,  day: 30),

                // ── July — Peak summer, tropical ────────────────────────────

        Artwork(id: "canoeLakeSunset",   fileName: "canoeLakeSunset",   displayName: "Stillness Before the Paddle Home",    completionMessage: "Birch bark canoes were sewn with spruce roots and sealed with pine pitch. No nails — the design hasn't changed in centuries.",        month: 7,  day: 1),
        Artwork(id: "tropicalFish",      fileName: "tropicalFish",      displayName: "Snow on the Bridge",          completionMessage: "Reef fish see ultraviolet patterns on each other invisible to us. The reef is louder than it looks.",                month: 7,  day: 2),
        Artwork(id: "shorebirdsFlats",    fileName: "shorebirdsFlats",    displayName: "Low Tide Reconnaissance",completionMessage: "Some shorebirds fly nonstop from Alaska to New Zealand. Eight days without landing, eating, or drinking.",               month: 7,  day: 3),
        Artwork(id: "fireworksLake",      fileName: "fireworksLake",      displayName: "Loud and Brief and Worth It",   completionMessage: "Fireworks were invented in China around 200 BC to scare off evil spirits. Color came about a thousand years later.", month: 7, day: 4),
        Artwork(id: "lanternRelease",        fileName: "lanternRelease",        displayName: "One Wish, One Light",    completionMessage: "Sky lanterns were originally military signals in 3rd-century China. They became wishes much later.",    month: 7,  day: 5),
        Artwork(id: "desertOasis",        fileName: "desertOasis",        displayName: "Mirage or Promise",           completionMessage: "Desert oases form where ancient aquifers reach the surface. Some have been the same green spot for ten thousand years.",        month: 7,  day: 6),
        Artwork(id: "galapagosTortoise",     fileName: "galapagosTortoise",     displayName: "Unhurried Since the Cenozoic",    completionMessage: "Galápagos tortoises can live to 175. Some alive today were born before the lightbulb was invented.",    month: 7,  day: 7),
        Artwork(id: "cabinGuitar",           fileName: "cabinGuitar",           displayName: "First String, Last Light",    completionMessage: "A guitar string vibrates at hundreds of frequencies at once. The body of the guitar quietly chooses which ones we hear.",    month: 7,  day: 8),
        Artwork(id: "volcanoIsland",     fileName: "volcanoIsland",      displayName: "Born from Beneath",         completionMessage: "Hawaii is still growing. The Big Island gains roughly forty new acres a year from active lava flows.",                              month: 7,  day: 9),
        Artwork(id: "jazzBalcony",           fileName: "jazzBalcony",           displayName: "Brass and Spanish Moss",    completionMessage: "New Orleans jazz emerged from a single neighborhood in the early 1900s. Within twenty years it had reshaped American music.",    month: 7,  day: 10),
        Artwork(id: "orcaBreaching",      fileName: "orcaBreaching",      displayName: "Thunder from the Deep",         completionMessage: "Orcas have distinct dialects per pod. The whale you'd hear off Iceland sounds nothing like the whale off Vancouver.",                        month: 7,  day: 11),
        Artwork(id: "jungleWaterfall",    fileName: "jungleWaterfall",    displayName: "Hidden in the Green",       completionMessage: "Waterfalls retreat upstream over time. Niagara has moved seven miles south in twelve thousand years.",                month: 7,  day: 12),
        Artwork(id: "keralaHouseboat",       fileName: "keralaHouseboat",       displayName: "Drifting Through the Palms",    completionMessage: "Kerala's houseboats started as rice barges — planks lashed together with coir rope. No nails, just careful knots.",    month: 7,  day: 13),
        Artwork(id: "tropicalWaterfall",  fileName: "tropicalWaterfall",  displayName: "Cascade into Warmth",     completionMessage: "Tropical waterfalls make their own weather. The spray cools the air around them by ten degrees, holding their own ecosystem.",                         month: 7,  day: 14),
        Artwork(id: "ospryDivingWaves",  fileName: "ospryDivingWaves",  displayName: "The Strike from Above",    completionMessage: "Ospreys close their nostrils when they dive and have a reversible outer toe. Built specifically for catching fish.",                    month: 7,  day: 15),
        Artwork(id: "coralReef",          fileName: "coralReef",          displayName: "Cardinal on the Ice",             completionMessage: "Coral reefs are built by tiny polyps, each smaller than a fingertip. A reef the size of a city block can contain a billion of them.",                month: 7,  day: 16),
        Artwork(id: "octopusTidePool",  fileName: "octopusTidePool",  displayName: "Eight Arms, No Plans",      completionMessage: "Octopuses have nine brains — one central, plus one in each arm. Each arm can solve problems on its own.",                       month: 7,  day: 17),
        Artwork(id: "fireEscapeReader",      fileName: "fireEscapeReader",      displayName: "Five Floors Up, Worlds Away",    completionMessage: "New York's fire escapes were mandated after the 1911 Triangle Shirtwaist fire. They became their own architecture — stairs, gardens, rooms with sky.",    month: 7,  day: 18),
        Artwork(id: "cliffClimber",          fileName: "cliffClimber",          displayName: "Chalk and Conviction",    completionMessage: "Sandstone climbing routes follow grain lines laid down millions of years ago. The climber is reading geology one fingertip at a time.",    month: 7,  day: 19),
        Artwork(id: "hammockBeach",       fileName: "hammockBeach",       displayName: "Between Two Palms",          completionMessage: "Hammocks were invented by the Maya about a thousand years ago. They kept sleepers safely above snakes and damp earth.",                        month: 7,  day: 20),
        Artwork(id: "junglePool",         fileName: "junglePool",         displayName: "Emerald and Shadow",            completionMessage: "Jungle pools are often nutrient-deserts. The water stays clear because most of the life is happening above, in the canopy.",                month: 7,  day: 21),
        Artwork(id: "cenoteDiver",           fileName: "cenoteDiver",           displayName: "Cathedral Below the Surface",    completionMessage: "Mexican cenotes were sacred to the Maya — portals to the underworld. Some have been used for ceremonies for two thousand years.",    month: 7,  day: 22),
        Artwork(id: "sandDunes",          fileName: "sandDunes",          displayName: "The Shape of Wind",             completionMessage: "Sand dunes hum when their grains shift in unison. Some have been recorded at over a hundred hertz — a low, deep organ note.",                        month: 7,  day: 23),
        Artwork(id: "strawberry",         fileName: "strawberry",         displayName: "Red and Ready",       completionMessage: "Strawberries technically aren't berries. The fruit is the swollen base of the flower; the seeds sit on the outside.",                              month: 7,  day: 24),
        Artwork(id: "beachHammockBooks",fileName: "beachHammockBooks",displayName: "No Schedule Until Monday",   completionMessage: "Reading on a beach is fairly recent. Books were too expensive to risk near sand until paperbacks were invented in 1935.",              month: 7,  day: 25),
        Artwork(id: "fennecFoxDesert", fileName: "fennecFoxDesert", displayName: "All Ears, All Desert",    completionMessage: "Fennec foxes can hear a beetle walking on sand from seventy meters. The big ears double as radiators in the desert heat.",    month: 7, day: 26),
        Artwork(id: "whaleWatchers",         fileName: "whaleWatchers",         displayName: "The Surface Breaks",    completionMessage: "Whale pods are often three generations of females — grandmothers, daughters, granddaughters. Multi-generational outings, in the open ocean.",    month: 7,  day: 27),
        Artwork(id: "mangroveShallows",    fileName: "mangroveShallows",    displayName: "Slow Grace Underwater",             completionMessage: "Manatees are most closely related to elephants, not seals. They evolved from a land-dwelling ancestor fifty million years ago.", month: 7,  day: 28),
        Artwork(id: "snorkelReef",           fileName: "snorkelReef",           displayName: "Breathing and Floating",    completionMessage: "Sea turtles return to the exact beach where they hatched, sometimes decades later. They navigate by Earth's magnetic field.",    month: 7,  day: 29),
        Artwork(id: "poppyFieldTree",   fileName: "poppyFieldTree",   displayName: "Poppies Without Reason",           completionMessage: "Poppies became symbols of remembrance after WWI — they were the first flowers to grow back on the disturbed battlefields.",                   month: 7,  day: 30),
        Artwork(id: "stargazingCampfire",fileName:"stargazingCampfire",displayName:"Small Fire, Infinite Sky",    completionMessage: "Most stars you see have already moved. Their light is years old; a few have already burned out by the time it reaches you.",                   month: 7,  day: 31),

                // ── August — Late summer, ocean life ────────────────────────

        Artwork(id: "dolphinLeaping",     fileName: "dolphinLeaping",     displayName: "Pure Speed, Pure Joy",        completionMessage: "Dolphins leap for play, communication, parasite removal, and to peek above the water. Often all at once.",                month: 8,  day: 1),
        Artwork(id: "blueJelly",          fileName: "blueJelly",          displayName: "Drifting Without Direction",         completionMessage: "Jellyfish are ninety-five percent water and have survived five mass extinctions. Less, somehow, is enough.",                           month: 8,  day: 2),
        Artwork(id: "lanternFestival",   fileName: "lanternFestival",    displayName: "A Sky Full of Wishes",       completionMessage: "Pingxi's lantern festival in Taiwan releases tens of thousands of lanterns at once, each carrying a written wish into the dark.",                    month: 8,  day: 3),
        Artwork(id: "stoatStoneWall",    fileName: "stoatStoneWall",    displayName: "The Weasel at the Wall",        completionMessage: "Stoats turn pure white in winter and are then called ermine. The black tail tip stays year-round.",                month: 8,  day: 4),
        Artwork(id: "mantaRay",           fileName: "mantaRay",           displayName: "Shadow of the Deep",              completionMessage: "Manta rays have the largest brain-to-body ratio of any fish. They recognize themselves in mirrors.",                               month: 8,  day: 5),
        Artwork(id: "ospreyDive",         fileName: "ospreyDive",         displayName: "Target Acquired",            completionMessage: "Ospreys spot fish through surface ripples by mentally adjusting for refraction in real time. Math, mid-flight.",                            month: 8,  day: 6),
        Artwork(id: "hedgehogAutumn",      fileName: "hedgehogAutumn",      displayName: "The Hedgehog Considers Autumn",          completionMessage: "Hedgehogs have about five thousand spines, each lasting a year before being replaced. The new ones grow in slowly.", month: 8,  day: 7),
        Artwork(id: "humpbackWhale",      fileName: "humpbackWhale",      displayName: "The Song Beneath Everything",         completionMessage: "A humpback's song travels ten thousand miles underwater. The whole ocean hears it. Today, so did you.",  month: 8,  day: 8),
        Artwork(id: "barnOwlHarvestMoon",       fileName: "barnOwlHarvestMoon",       displayName: "Barn Owl at the Orange Moon",           completionMessage: "Barn owls hunt in total darkness using only sound. Their disc-shaped face funnels sound to ears placed at slightly different heights.",      month: 8,  day: 9),
        Artwork(id: "slothRainforest",    fileName: "slothRainforest",    displayName: "No Rush, No Regrets",    completionMessage: "Sloths grow algae in their fur. Certain moths live nowhere else. A whole tiny ecosystem, traveling slowly.",                             month: 8,  day: 10),
        Artwork(id: "poisonDartFrogRed", fileName: "poisonDartFrogRed", displayName: "Small, Bright, and Lethal",    completionMessage: "Poison dart frogs only get their toxin from wild insects. Raised in captivity, they're completely harmless.",    month: 8, day: 11),
        Artwork(id: "fountain",           fileName: "fountain",           displayName: "The Center of the Square",        completionMessage: "Roman fountains were powered by gravity alone, fed from aqueducts miles away. The same engineering still works in many old cities.",                 month: 8,  day: 12),
        Artwork(id: "obonLanterns",       fileName: "obonLanterns",       displayName: "Light for the Returning",       completionMessage: "Obon is Japan's festival for ancestral spirits. The lanterns guide them back to the other world after a brief visit home.",       month: 8,  day: 13),
        Artwork(id: "mountainRowboat",    fileName: "mountainRowboat",    displayName: "Two Oars, One Direction",       completionMessage: "Rowing is one of the few exercises that uses every major muscle group. It also predates the wheel.",                    month: 8,  day: 14),
        Artwork(id: "kelpForest",          fileName: "kelpForest",          displayName: "Cathedral of Green Light",            completionMessage: "Giant kelp grows up to two feet a day and reaches a hundred and seventy-five feet tall. The fastest-growing organism on Earth.",               month: 8,  day: 15),
        Artwork(id: "pelicanColorful",    fileName: "pelicanColorful",    displayName: "The Absurd and Excellent",                completionMessage: "A pelican's pouch holds three gallons of water. It strains the catch by tipping back and letting the water drain out.",                   month: 8,  day: 16),
        Artwork(id: "moonlitHarbor",      fileName: "moonlitHarbor",      displayName: "Reflections After Dark",         completionMessage: "Lighthouses started as coal fires, then oil lamps, then bulbs. Their shape has barely changed in two thousand years.",                  month: 8,  day: 17),
        Artwork(id: "stormPetrelSea",     fileName: "stormPetrelSea",     displayName: "Dancing at the Edge",    completionMessage: "Storm petrels can drink seawater. They excrete excess salt through their nostrils as they fly.",          month: 8,  day: 18),
        Artwork(id: "alpineMeadow",       fileName: "alpineMeadow",       displayName: "Above the Treeline",          completionMessage: "Alpine wildflowers compress a full season's growth into eight weeks. They bloom, seed, and die before the snow returns.",                     month: 8,  day: 19),
        Artwork(id: "desertMesa",         fileName: "desertMesa",         displayName: "Ancient, Flat, and Patient",            completionMessage: "Mesas form when a hard rock cap protects softer rock below. As the surrounding land erodes, the mesa stays standing.",                   month: 8,  day: 20),
        Artwork(id: "grizzlySalmon",     fileName: "grizzlySalmon",      displayName: "The Brief Abundance",  completionMessage: "A grizzly can eat forty salmon a day during the run. The leftovers fertilize entire forests — bear-borne nutrients.",                          month: 8,  day: 21),
        Artwork(id: "desertAstronomer",      fileName: "desertAstronomer",      displayName: "Alone with the Whole Sky",    completionMessage: "The Atacama Desert is so dry and clear that some of its weather stations have never recorded rain. The world's best stargazing.",    month: 8,  day: 22),
        Artwork(id: "pirateShip",        fileName: "pirateShip",         displayName: "The Black Flag",            completionMessage: "Pirate ships ran by surprisingly democratic codes. Captains were elected, plunder was shared, and contracts protected injured crew.", month: 8, day: 23),
        Artwork(id: "karstFisherman",        fileName: "karstFisherman",        displayName: "Between the Peaks",    completionMessage: "The karst peaks of southern China are limestone sculpted by acid rain over millennia. Sharp because they're young, geologically.",    month: 8,  day: 24),
        Artwork(id: "autumnLodgeTwilight",    fileName: "autumnLodgeTwilight",    displayName: "The Cabin in Amber Water",        completionMessage: "Lakes go glass-still at dusk because the air cools faster than the water, removing the breezes that ripple the surface.",                month: 8,  day: 25),
        Artwork(id: "marshlandDawn",     fileName: "marshlandDawn",     displayName: "The First Light, Unhurried",      completionMessage: "Marshes filter more pollutants per acre than any other ecosystem. We drained them for centuries before figuring that out.",  month: 8,  day: 26),
        Artwork(id: "wildTurkeyLeaves",          fileName: "wildTurkeyLeaves",          displayName: "Turkey in the Fallen Leaves",             completionMessage: "Wild turkeys can fly. The domestic ones can't — centuries of breeding for breast size grounded them.",             month: 8,  day: 27),
        Artwork(id: "pheasantWheat", fileName: "pheasantWheat", displayName: "The Pheasant's Stroll",    completionMessage: "Ring-necked pheasants come from China. They were introduced to North America in 1881 and have run the wheat fields ever since.",       month: 8,  day: 28),
        Artwork(id: "autumnHarvestField",  fileName: "autumnHarvestField",  displayName: "Ladder in the Last Light",          completionMessage: "There are over seventy-five hundred apple varieties worldwide. Your grocery store carries about a dozen of them.",            month: 8,  day: 29),
        Artwork(id: "badgerBurrow",    fileName: "badgerBurrow",    displayName: "The Badger at the Burrow",            completionMessage: "Badger setts are ancient. Some have been dug in the same spot for hundreds of years, each generation adding tunnels.",                    month: 8,  day: 30),
        Artwork(id: "lightningSunflowers",      fileName: "lightningSunflowers",      displayName: "Lightning Over Sunflowers",               completionMessage: "Lightning strikes the earth roughly a hundred times every second. Almost none of it ever touches a person.",       month: 8,  day: 31),

                // ── September — Transition, birds ───────────────────────────

        Artwork(id: "japanesePagoda",     fileName: "japanesePagoda",     displayName: "Tiers to Stillness",        completionMessage: "Five-story pagodas flex in earthquakes — each floor sways independently, like a stack of trays. A thousand years of proof that bending beats breaking.",                      month: 9,  day: 1),
        Artwork(id: "baldEagle",          fileName: "baldEagle",          displayName: "The Symbol, The Bird",             completionMessage: "Bald eagles can spot a rabbit from two miles up. Their eyes have two focal points — one for distance, one for periphery — like built-in binoculars.",                 month: 9,  day: 2),
        Artwork(id: "countyFairSunset", fileName: "countyFairSunset", displayName: "Cotton Candy Light",   completionMessage: "Cotton candy was co-invented by a dentist in 1897. He called it Fairy Floss. It outsold everything else at the 1904 World's Fair.",      month: 9,  day: 3),
        Artwork(id: "coastalTidePools",   fileName: "coastalTidePools",   displayName: "Stranded by the Tide",     completionMessage: "Tide pools hold more species per square foot than most ocean zones. Everything in them adapted to survive both underwater and in open air, twice a day.",                        month: 9,  day: 4),
        Artwork(id: "cellistSkyline",       fileName: "cellistSkyline",       displayName: "The Cellist and the City",           completionMessage: "The cello's range sits closest to the human voice of any instrument. Something about its timbre bypasses the brain and goes straight to the chest.",               month: 9,  day: 5),
        Artwork(id: "coastalCliffs",      fileName: "coastalCliffs",      displayName: "The Long Drop to the Sea",         completionMessage: "Sea cliffs erode at roughly a centimeter a year — fast enough that coastlines in old maps no longer match the land. The sea is always editing.",                 month: 9,  day: 6),
        Artwork(id: "eagleSouring",       fileName: "eagleSouring",       displayName: "Thermal Climbing",          completionMessage: "Eagles ride thermals — columns of warm rising air — and can glide for hours without a single wingbeat. The sky does the work.",                        month: 9,  day: 7),
        Artwork(id: "pandaBamboo",       fileName: "pandaBamboo",        displayName: "Lunch for Six Hours",       completionMessage: "Pandas evolved a sixth finger — a modified wrist bone — just to grip bamboo. Forty pounds a day, sixteen hours of chewing. Total commitment to one menu.",              month: 9,  day: 8),
        Artwork(id: "moroccanSouk",       fileName: "moroccanSouk",       displayName: "The Maze of Colors",          completionMessage: "The souks of Fez have operated in roughly the same layout for a thousand years. Dyers, tanners, and spice sellers each have their quarter. The city memorized itself.",                                month: 9,  day: 9),
        Artwork(id: "observatory",        fileName: "observatory",        displayName: "Pointed at the Dark",            completionMessage: "Observatories are painted white to stay cool — even tiny temperature differences create air currents that blur the view. Patience starts with the building.",                 month: 9,  day: 10),
        Artwork(id: "parrot",             fileName: "parrot",             displayName: "Unsolicited Opinions",                 completionMessage: "African grey parrots don't just mimic — they use words in context, answer questions, and express preferences. One named Alex asked his researcher what color he was.",                      month: 9,  day: 11),
        Artwork(id: "candyShop",          fileName: "candyShop",          displayName: "Sugar and Consequence",             completionMessage: "Rock candy is one of the oldest confections — crystallized sugar on a string, unchanged since the ninth century. Some recipes don't need improving.",            month: 9,  day: 12),
        Artwork(id: "tidePoolStarfish",  fileName: "tidePoolStarfish",  displayName: "Five Arms, Zero Concern",              completionMessage: "Some starfish can regenerate their entire body from a single severed arm. No brain, no blood, no bones — and still one of the most resilient animals in the ocean.",   month: 9,  day: 13),
        Artwork(id: "trainRicePaddies",      fileName: "trainRicePaddies",      displayName: "Window Seat, Passing Green",    completionMessage: "Rice paddies are flooded on purpose — the standing water suppresses weeds and creates an ecosystem where fish, frogs, and rice all thrive together.",    month: 9,  day: 14),
        Artwork(id: "cathedralInterior",  fileName: "cathedralInterior",  displayName: "Light Falling Through Stone",     completionMessage: "Medieval stained glass gets its blue from cobalt, its red from gold, its green from copper. The windows were a village's most expensive artwork — and its only movie screen.",                          month: 9,  day: 15),
        Artwork(id: "clockworkGears",    fileName: "clockworkGears",    displayName: "Everything Turning Together",       completionMessage: "The oldest working clock sits in Salisbury Cathedral, ticking since 1386. No face, no hands — it just rings a bell. Six hundred years of keeping one promise.",                         month: 9,  day: 16),
        Artwork(id: "romanAqueduct",      fileName: "romanAqueduct",      displayName: "Water Across the Ages",         completionMessage: "Roman aqueducts slope just one centimeter per thirty meters — precisely enough that gravity alone moved water across entire valleys. Some still carry water today.",            month: 9,  day: 17),
        Artwork(id: "watchTower",         fileName: "watchTower",         displayName: "Scanning the Horizon",      completionMessage: "Some fire lookout towers in the American West are still staffed by solitary watchers who spend months alone, scanning for smoke. The view is the entire job.",     month: 9,  day: 18),
        Artwork(id: "toucanPerched",      fileName: "toucanPerched",      displayName: "The Impractical Beak",                 completionMessage: "A toucan's beak looks heavy but it's mostly hollow — keratin over a foam of tiny bone struts. Lighter than it looks, and threaded with blood vessels that release heat.",                       month: 9,  day: 19),
        Artwork(id: "japaneseGardenKoi",fileName: "japaneseGardenKoi",displayName: "Slow Circles in Still Water",         completionMessage: "The oldest known koi lived to 226 years — a fish named Hanako in Japan, born in 1751. Her age was confirmed by growth rings in her scales, like a tree.",        month: 9,  day: 20),
        Artwork(id: "potteryWorkshop",    fileName: "potteryWorkshop",    displayName: "Clay and Patience",       completionMessage: "The potter's wheel was invented a thousand years before anyone thought to put a wheel on a cart. Shaping clay came first. Moving heavy things came later.",               month: 9,  day: 21),
        Artwork(id: "roadrunner",         fileName: "roadrunner",         displayName: "Gone Before You Look",             completionMessage: "Roadrunners eat rattlesnakes. They grab them behind the head, whip them against rocks, and swallow them whole. Twenty miles per hour and absolutely fearless.",                     month: 9,  day: 22),
        Artwork(id: "autumnStonehenge",  fileName: "autumnStonehenge",  displayName: "The Old Stones in October",      completionMessage: "Stonehenge's inner bluestones came from Wales — a hundred and fifty miles away. How Neolithic people moved four-ton stones that far is still genuinely debated.",                      month: 9,  day: 23),
        Artwork(id: "auroraLakeshore",     fileName: "auroraLakeshore",     displayName: "Eagle Above the River Valley",              completionMessage: "The aurora happens when solar wind hits Earth's magnetic field and excites atmospheric gases. Jupiter has auroras too — thousands of times more powerful than ours.",                      month: 9,  day: 24),
        Artwork(id: "cormorantHarbor",    fileName: "cormorantHarbor",    displayName: "Cormorant at Harbor's End",            completionMessage: "Cormorants spread their wings to dry because their feathers aren't fully waterproof. The trade-off: they dive deeper and swim faster underwater than almost any bird.",                         month: 9,  day: 25),
        Artwork(id: "desertTortoise",fileName: "desertTortoise",displayName: "Desert Tortoise in Sunburst",   completionMessage: "Desert tortoises store up to a year's worth of water in their bladder. They've survived in the Mojave for millions of years — longer than the desert has been dry.",     month: 9,  day: 26),
        Artwork(id: "egretGoldenWater",        fileName: "egretGoldenWater",        displayName: "Egret in the Golden Water",              completionMessage: "Egrets were nearly hunted to extinction in the 1890s for their plumage feathers — used in women's hats. The outcry that saved them launched the modern conservation movement.",                     month: 9,  day: 27),
        Artwork(id: "seedlingGreenhouse", fileName: "seedlingGreenhouse", displayName: "Seedlings in the Greenhouse",         completionMessage: "The world's backup plan for agriculture sits inside a mountain in Svalbard — a vault holding over a million seed samples from every continent. Quiet insurance against everything.",               month: 9,  day: 28),
        Artwork(id: "emeraldRainforest",   fileName: "emeraldRainforest",   displayName: "Green Upon Green",            completionMessage: "The Amazon generates half its own rainfall. Trees pull water from the soil, breathe it into the air, and it falls again as rain. The forest waters itself.",                        month: 9,  day: 29),
        Artwork(id: "mushroomForager",       fileName: "mushroomForager",       displayName: "Crouching in the Old Growth",    completionMessage: "Chanterelles can't be farmed. They grow only in partnership with living tree roots, trading nutrients underground. Every chanterelle on a plate was found, not grown.",    month: 9,  day: 30),

                // ── October — Peak autumn ───────────────────────────────────

        Artwork(id: "purpleMoose",        fileName: "purpleMoose",        displayName: "The Violet Wanderer",           completionMessage: "A moose's antlers can span six feet and weigh forty pounds. They shed and regrow every year — the fastest-growing bone tissue in the animal kingdom.",                        month: 10, day: 1),
        Artwork(id: "moose",              fileName: "moose",              displayName: "Lord of the Willows",                  completionMessage: "Moose are strong swimmers and can dive nearly twenty feet to eat aquatic plants. They're the only deer species that can close their nostrils underwater.",                 month: 10, day: 2),
        Artwork(id: "midAutumnMoon",     fileName: "midAutumnMoon",     displayName: "Round Things Under a Round Moon", completionMessage: "The Mid-Autumn Festival celebrates the harvest moon — the full moon closest to the autumn equinox. Families share mooncakes and watch the same moon, together apart.",             month: 10, day: 3),
        Artwork(id: "ancientRuins",       fileName: "ancientRuins",       displayName: "What Centuries Forget",          completionMessage: "Most ancient ruins survived not because they were strong, but because they were forgotten. Cities built on top preserved them better than any protection could.",                     month: 10, day: 4),
        Artwork(id: "autumnOrchard",      fileName: "autumnOrchard",      displayName: "The Heavy Boughs",         completionMessage: "An apple tree takes four to eight years to bear its first fruit. Once it does, it can keep producing for a hundred years — patient investment, long return.",                month: 10, day: 5),
        Artwork(id: "greatWallAutumn",   fileName: "greatWallAutumn",   displayName: "A Million Hands Built This",      completionMessage: "The Great Wall was built over two thousand years by multiple dynasties. Some sections are made of stamped earth, not stone — held together by sticky rice mortar.",              month: 10, day: 6),
        Artwork(id: "mountainGoat",       fileName: "mountainGoat",       displayName: "Effortless on the Edge",          completionMessage: "Mountain goats have rubbery, concave hooves that grip rock like suction cups. They climb near-vertical cliffs to reach mineral deposits and escape predators.",                       month: 10, day: 7),
        Artwork(id: "catBookshopMidnight",fileName:"catBookshopMidnight",displayName:"The Night Bibliophile",    completionMessage: "Bookshop cats have a long history — originally kept to protect inventory from mice. Most stayed because they liked the shelves. The tradition outlived the mice.",    month: 10, day: 8),
        Artwork(id: "gazelleSavanna",     fileName: "gazelleSavanna",     displayName: "Grace Under Pressure",                completionMessage: "Gazelles use a behavior called stotting — bouncing high with stiff legs when a predator appears. It signals fitness: I saw you, and I'm fast enough not to care.",                                 month: 10, day: 9),
        Artwork(id: "autumnBarn",        fileName: "autumnBarn",          displayName: "Red in the Amber Light",           completionMessage: "Barns are red because Scandinavian farmers mixed rust into their sealant to prevent rot. The tradition crossed the Atlantic with immigrants and stuck.",               month: 10, day: 10),
        Artwork(id: "redCoveredBridge",   fileName: "redCoveredBridge",   displayName: "The Painted Crossing",     completionMessage: "Covered bridges were roofed to protect the structural timbers, not the travelers. An uncovered bridge lasts ten years; a covered one can last eighty.",                        month: 10, day: 11),
        Artwork(id: "sleepyFox",          fileName: "sleepyFox",          displayName: "Curled Against the Cold",             completionMessage: "Foxes wrap their tails over their noses when they sleep — the bushy fur acts as a warm air filter. A built-in blanket, attached.",                               month: 10, day: 12),
        Artwork(id: "birchTreesAutumn",   fileName: "birchTreesAutumn",   displayName: "The Gold Cathedral",  completionMessage: "Birch bark contains betulin, a waxy compound that makes it waterproof and slow to decay. Indigenous peoples across the Northern Hemisphere used it for canoes, shelters, and writing.",                   month: 10, day: 13),
        Artwork(id: "bison",              fileName: "bison",              displayName: "Weight of the Prairie",                  completionMessage: "Bison face into blizzards instead of turning away. Walking into the wind gets them through the storm faster. The hard direction is sometimes the short one.",                             month: 10, day: 14),
        Artwork(id: "tigerStalking",      fileName: "tigerStalking",      displayName: "Patient and Burning",                  completionMessage: "Tigers are ambush hunters — they stalk within thirty feet before charging. Each tiger's stripe pattern is unique, like a fingerprint pressed into fur.",               month: 10, day: 15),
        Artwork(id: "birchCanoe",         fileName: "birchCanoe",         displayName: "Still Water, Bright Fire",    completionMessage: "Birch bark canoes weigh under seventy pounds and can carry ten times their own weight. Light enough to portage, strong enough to cross a lake.",    month: 10, day: 16),
        Artwork(id: "amsterdamCyclist",      fileName: "amsterdamCyclist",      displayName: "Leaves in the Spokes",    completionMessage: "Amsterdam has more bicycles than people — roughly 880,000 bikes for 870,000 residents. About fifteen thousand are fished out of the canals every year.",    month: 10, day: 17),
        Artwork(id: "bridgeAutumn",       fileName: "bridgeAutumn",       displayName: "Reflection Season",  completionMessage: "Still water reflects almost perfectly because surface tension creates a natural mirror. Wind above two miles per hour is enough to break the illusion.",                          month: 10, day: 18),
        Artwork(id: "autumnBench",        fileName: "autumnBench",        displayName: "Waiting for No One",           completionMessage: "The oldest public benches in Europe date to medieval churchyards — placed so parishioners could rest between services. The tradition of sitting and watching predates parks.",                  month: 10, day: 19),
        Artwork(id: "diwaliDiyas",        fileName: "diwaliDiyas",        displayName: "A Thousand Small Flames",       completionMessage: "Diwali's oil lamps — diyas — are made of clay and filled with mustard or sesame oil. Families line them along windowsills, staircases, and rooftops to welcome light home.",                            month: 10, day: 20),
        Artwork(id: "autumnForestPath",  fileName: "autumnForestPath",   displayName: "Into the Amber Haze",    completionMessage: "Leaves don't actually change color in autumn — the yellow and orange were there all along, hidden by chlorophyll. Fall just reveals what summer covered up.",                month: 10, day: 21),
        Artwork(id: "birdFish",           fileName: "birdFish",           displayName: "Two Worlds, One Line",          completionMessage: "Kingfishers dive with almost no splash. Their beak shape inspired the nose of Japan's bullet train, solving a sonic boom problem at tunnel exits.",                          month: 10, day: 22),
        Artwork(id: "bioluminescentBay", fileName: "bioluminescentBay",  displayName: "The Sea Remembers Light",     completionMessage: "Bioluminescent bays glow because of dinoflagellates — tiny organisms that flash blue when the water moves. Every paddle stroke triggers a small galaxy.",                     month: 10, day: 23),
        Artwork(id: "autumnParkBench",   fileName: "autumnParkBench",   displayName: "Still Afternoon",      completionMessage: "The first public parks were royal hunting grounds opened to commoners. The bench, the path, the pond — all inherited from landscapes designed for kings.",  month: 10, day: 24),
        Artwork(id: "henChicksGoldenHour",   fileName: "henChicksGoldenHour",   displayName: "Dusk at the Henhouse",           completionMessage: "Hens talk to their chicks before they hatch — clucking softly through the shell. By the time the eggs open, the chicks already know their mother's voice.", month: 10,  day: 25),
        Artwork(id: "pumpkinPatchScarecrow", fileName: "pumpkinPatchScarecrow", displayName: "Guardian of the Gourds",        completionMessage: "Pumpkins are technically berries — botanists classify them as pepos, alongside watermelons and cucumbers. The largest on record weighed over twenty-eight hundred pounds.",       month: 10, day: 26),
        Artwork(id: "hauntedMansionDusk", fileName: "hauntedMansionDusk", displayName: "The House Has Opinions",         completionMessage: "Houses creak more at night because dropping temperatures cause wood and metal to contract. The sounds are real — just physics, not ghosts.",          month: 10, day: 27),
